String? istmoImageAssetFile(String productKey) {
  final mapped = istmoProductImages[productKey];
  if (mapped == null) return null;
  if (mapped.startsWith('cat_')) {
    return istmoCategoryImages[mapped];
  }
  return mapped;
}
